'use client';

import { useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { apiClient } from '@/lib/api';
import Button from '@/components/Button';
import Input from '@/components/Input';

export default function Dashboard() {
  const router = useRouter();
  const [habits, setHabits] = useState([]);
  const [habitName, setHabitName] = useState('');
  const [loading, setLoading] = useState(true);
  const [streaks, setStreaks] = useState({});
  const [analytics, setAnalytics] = useState(null);

  // Load habits when component mounts
  useEffect(() => {
    const token = apiClient.getToken();
    if (!token) {
      router.push('/login');
    } else {
      loadHabits();
    }
  }, []);

  // Load all data from backend
  const loadHabits = async () => {
    try {
      // Get habits
      const data = await apiClient.getHabits();
      setHabits(data.habits);
      
      // Get streaks for each habit
      const streakPromises = data.habits.map(h => 
        apiClient.getStreak(h.id).then(s => ({ id: h.id, streak: s }))
      );
      const streaksData = await Promise.all(streakPromises);
      
      // Convert array to object for easy lookup
      const streaksObj = {};
      streaksData.forEach(s => streaksObj[s.id] = s.streak);
      setStreaks(streaksObj);
      
      // Get analytics
      const analyticsData = await apiClient.getAnalytics();
      setAnalytics(analyticsData);
      
    } catch (err) {
      console.error('Error loading habits:', err);
      router.push('/login');
    } finally {
      setLoading(false);
    }
  };

  // Add new habit
  const addHabit = async () => {
    if (!habitName.trim()) return;
    
    try {
      await apiClient.createHabit(habitName);
      setHabitName('');
      loadHabits(); // Reload to show new habit
    } catch (err) {
      alert('Error: ' + err.message);
    }
  };

  // Delete habit
  const deleteHabit = async (id) => {
    if (!confirm('Delete this habit?')) return;
    
    try {
      await apiClient.deleteHabit(id);
      loadHabits(); // Reload after delete
    } catch (err) {
      alert('Error: ' + err.message);
    }
  };

  // Mark habit as complete
  const completeHabit = async (id) => {
    try {
      await apiClient.completeHabit(id);
      loadHabits(); // Reload to update streaks
    } catch (err) {
      alert('Error: ' + err.message);
    }
  };

  // Logout user
  const logout = () => {
    apiClient.logout();
    router.push('/login');
  };

  // Show loading spinner
  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-100">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-indigo-600 mx-auto mb-4"></div>
          <p className="text-gray-600">Loading your habits...</p>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-100">
      
      {/* Header */}
      <header className="bg-white shadow-md">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4">
          <div className="flex justify-between items-center">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 bg-indigo-600 rounded-lg flex items-center justify-center">
                <span className="text-white text-xl">📊</span>
              </div>
              <div>
                <h1 className="text-2xl font-bold text-gray-900">Habit Tracker</h1>
                <p className="text-sm text-gray-600">Track your daily habits</p>
              </div>
            </div>
            <Button onClick={logout} variant="outline" size="sm">
              Logout
            </Button>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        
        {/* Analytics Cards */}
        {analytics && (
          <div className="grid md:grid-cols-3 gap-6 mb-8">
            
            {/* Total Habits Card */}
            <div className="bg-white p-6 rounded-xl shadow-md text-center">
              <p className="text-4xl font-bold text-indigo-600">
                {analytics.total_habits}
              </p>
              <p className="text-gray-600 mt-2">Total Habits</p>
            </div>
            
            {/* Total Completions Card */}
            <div className="bg-white p-6 rounded-xl shadow-md text-center">
              <p className="text-4xl font-bold text-green-600">
                {analytics.total_completions}
              </p>
              <p className="text-gray-600 mt-2">Total Completions</p>
            </div>
            
            {/* Success Rate Card */}
            <div className="bg-white p-6 rounded-xl shadow-md text-center">
              <p className="text-4xl font-bold text-purple-600">
                {analytics.completion_rate}%
              </p>
              <p className="text-gray-600 mt-2">Success Rate</p>
            </div>
          </div>
        )}

        {/* Add Habit Form */}
        <div className="bg-white p-6 rounded-xl shadow-md mb-8">
          <h2 className="text-xl font-bold text-gray-900 mb-4">Add New Habit</h2>
          <div className="flex gap-2">
            <Input
              placeholder="e.g., Exercise, Read, Meditate"
              value={habitName}
              onChange={(e) => setHabitName(e.target.value)}
              onKeyPress={(e) => e.key === 'Enter' && addHabit()}
              className="flex-1"
            />
            <Button 
              onClick={addHabit} 
              variant="primary"
              disabled={!habitName.trim()}
            >
              Add Habit
            </Button>
          </div>
        </div>

        {/* Habits Grid */}
        {habits.length > 0 ? (
          <div>
            <h2 className="text-2xl font-bold text-gray-900 mb-4">Your Habits</h2>
            <div className="grid md:grid-cols-3 gap-6">
              {habits.map(habit => (
                <div 
                  key={habit.id} 
                  className="bg-white p-6 rounded-xl shadow-md hover:shadow-lg transition-shadow"
                >
                  
                  {/* Habit Header */}
                  <div className="flex items-center justify-between mb-4">
                    <h3 className="text-lg font-bold text-gray-900">
                      {habit.name}
                    </h3>
                    <button
                      onClick={() => deleteHabit(habit.id)}
                      className="text-red-500 hover:text-red-700 text-xl font-bold"
                      title="Delete habit"
                    >
                      ×
                    </button>
                  </div>
                  
                  {/* Streak Display */}
                  {streaks[habit.id] && (
                    <div className="mb-4 p-3 bg-gray-50 rounded-lg">
                      <p className="text-sm text-gray-600">Current Streak</p>
                      <p className="text-3xl font-bold text-indigo-600">
                        {streaks[habit.id].current} 🔥
                      </p>
                      <p className="text-xs text-gray-500 mt-1">
                        Best: {streaks[habit.id].longest} days
                      </p>
                    </div>
                  )}
                  
                  {/* Complete Button */}
                  <Button
                    onClick={() => completeHabit(habit.id)}
                    variant="success"
                    fullWidth
                  >
                    ✓ Mark Complete
                  </Button>
                </div>
              ))}
            </div>
          </div>
        ) : (
          <div className="text-center py-16 bg-white rounded-xl shadow-md">
            <div className="text-6xl mb-4">📝</div>
            <h3 className="text-xl font-bold text-gray-900 mb-2">
              No Habits Yet
            </h3>
            <p className="text-gray-600 mb-6">
              Start by adding your first habit above!
            </p>
          </div>
        )}
      </main>
    </div>
  );
}